    {
      "expectation_id": "提供每次轻症赔付金额比例",
      "description": "用户明确询问每次赔多少，答案须说明赔付比例",
      "acceptance_criteria": "答案中包含比例范围（如20%-30%）或具体比例数字",
      "blocking_level": "blocking"
