      "expectation_id": "提及间隔期要求",
      "description": "提醒用户两次轻症理赔之间通常存在间隔期",
      "acceptance_criteria": "答案中提及“间隔期”字样",
      "blocking_level": "non-blocking"
    },
    {
      "expectation_id": "说明轻症责任的其他重要限制",
      "description": "提及可能存在的分组限制、累计赔付上限、重疾保额变化等，以帮助用户全面理解",
      "acceptance_criteria": "答案中至少提到分组、累计上限、保额减少等限制之一",
      "blocking_level": "non-blocking"
    },
    {
      "expectation_id": "引导用户查阅保险合同",
      "description": "由于不同合同条款不同，答案必须引导用户查阅自己的合同以获取准确信息",
      "acceptance_criteria": "答案中包含“查阅合同”、“合同条款”或“咨询客服”等指引",
      "blocking_level": "blocking"
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "直接回答轻症是否多次赔付",
      "status": "fulfilled",
      "reason": "答案明确表示“轻症可以赔付多次”，直接回应用户问题"
    },
    {
      "expectation_id": "提供轻症赔付次数上限示例",
      "status": "fulfilled",
      "reason": "答案提到“可能有次数上限（如3次或5次）”，提供了具体示例"
    },
    {
      "expectation_id": "提供每次轻症赔付金额比例",
      "status": "fulfilled",
      "reason": "答案明确给出“每次赔付金额通常为基本保险金额的20%至30%”"
    },
    {
      "expectation_id": "提及间隔期要求",
      "status": "fulfilled",
      "reason": "答案中提到了“间隔期要求”"
    },
