    "within_evaluable_scope": true,
    "evaluable_errors": [],
    "uncontrollable_limits": []
  },
  "evaluation_boundary": {
    "scenario": "qa_gold_answer",
    "allowed_evidence": ["参考黄金回答", "问题文本"],
    "restrictions": "不依赖外部知识库，仅比较参考回答与实际回答"
  },
  "missing": [
    {
      "description": "轻症责任可能存在的分组限制、累计赔付上限或重疾保额变化等限制",
      "expectation_id": "说明轻症责任的其他重要限制",
      "impact": "non-blocking"
    }
  ],
  "wrong": [],
  "extra": [],
  "evidence": [
    {
      "type": "reference_answer",
      "content": "参考回答中明确说明了轻症赔付次数、比例、间隔期、分组限制和合同查阅建议",
      "relevant_expectations": [
        "直接回答轻症是否多次赔付",
        "提供轻症赔付次数上限示例",
        "提供每次轻症赔付金额比例",
        "提及间隔期要求",
        "说明轻症责任的其他重要限制",
        "引导用户查阅保险合同"
      ]
    },
    {
      "type": "actual_answer",
      "content": "实际答案包含了多次赔付、比例、次数上限示例、间隔期和合同查阅，但未提及分组等其他限制",
      "relevant_expectations": [
        "直接回答轻症是否多次赔付",
        "提供轻症赔付次数上限示例",
        "提供每次轻症赔付金额比例",
        "提及间隔期要求",
        "说明轻症责任的其他重要限制",
        "引导用户查阅保险合同"
      ]
    }
  ],
  "reasoning_summary": "用户核心问题为轻症能否多次赔付及每次赔付金额。实际答案明确确认了多次赔付，给出了20%-30%的赔付比例，并提供了3次或5次的次数上限示例及间隔期提醒，最后引导用户查阅合同。关键信息均准确且符合一般保险规则。唯一不足是未提及参考回答中提到的分组限制、累计赔付上限或重疾保额变化等额外限制。但鉴于这些限制并非用户直接询问内容，且答案中已通过“建议查阅合同”进行兜底，整体回答满足了用户的核心需求。因此评估为通过，但完整性稍显不足。",
  "needs_human_review": false,
  "scenario": "qa_gold_answer",
  "quality_flags": ["次要限制信息缺失"]
}

